input.old_string:
.ad {
  width: 1080px;
  height: 1080px;
  position: absolute;
  top: 0; left: 0;
  transform-origin: top left;
  background: #c0111f;
  overflow: hidden;
}

/* BG texture */
.ad::before {
  content: '';
  position: absolute; inset: 0;
  background:
    radial-gradient(ellipse at 50% 40%, #e8182a 0%, #9b0a16 55%, #6b0010 100%);
  z-index: 0;
}
.ad::after {
  content: '';
  position: absolute; inset: 0;
  background-image: radial-gradient(circle, rgba(255,255,255,0.04) 1px, transparent 1px);
  background-size: 28px 28px;
  z-index: 1;
}

.ad-inner { position: relative; z-index: 2; width: 100%; height: 100%; display: flex; flex-direction: column; }

